 33→    public function __construct(
 34→        EntityManagerInterface $entityManager,
 35→        string $modeConfigManager,
 36→        string $environment,
 37→        string $instanceName
 38→    ) {
 39→        $this->entityManager = $entityManager;
 40→        $this->mode          = $modeConfigManager;
 41→
 42→        $this->currentEnvironnement        = $environment;
 43→        $this->currentWebinstanceShortname = $instanceName;
 44→
 45→        $this->init();
 46→    }
