 48→    /**
 49→     * @throws \RedisException
 50→     * @throws \Exception
 51→     */
 52→    public function init(string $webinstance_shortname = null): void
 53→    {
 54→        if (null !== $webinstance_shortname) {
 55→            $this->currentWebinstanceShortname = $webinstance_shortname;
 56→        }
 57→
 58→        $this->cfgIdent = $this->currentEnvironnement.'-'.$this->currentWebinstanceShortname;
 59→        $this->cacheKey = 'rp_'.$this->currentEnvironnement.'_'.$this->currentWebinstanceShortname.'_cfgman';
 60→
 61→        $this->initRedisCache();
 62→        $this->loadConfigValues();
 63→    }
 64→
 65→    protected function initRedisCache(): void
 66→    {
 67→        $this->redisCache = RedisAdapter::createConnection(getenv('REDIS_DSN'));
 68→    }
 69→
 70→    /**
 71→     * function to find a key configuration.
 72→     *
 73→     * @param $key
 74→     *
 75→     * @return \DateTime|float|int
 76→     *
 77→     * @deprecated
 78→     */
 79→    public function get($key)
 80→    {
 81→        $this->checkIfKeyExistOrCreateException($key);
 82→
 83→        return $this->getDecodedValue($this->arrayConfigValue[$this->cfgIdent][$key]);
 84→    }
 85→
 86→    /**
 87→     * function for determining whether a key exist.
 88→     *
 89→     * @throws \RedisException
 90→     */
 91→    public function has(string $key): bool
 92→    {
 93→        if (!\is_array($this->arrayConfigValue[$this->cfgIdent])) {
 94→            $this->loadConfigValues();
 95→        }
 96→
 97→        return \array_key_exists($key, $this->arrayConfigValue[$this->cfgIdent]);
