187→    /**
188→     * @param $key
189→     * @param array $default
190→     * @param array $jsonKeyValue
191→     *
192→     * @return array|\DateTime|float|int|string
193→     *
194→     * @throws \RedisException
195→     */
196→    public function getJsonOption($key, $default = [], $jsonKeyValue = [])
197→    {
198→        if ($this->has($key)) {
199→            $decodedValue = $this->getDecodedValue($this->arrayConfigValue[$this->cfgIdent][$key]);
200→            // Convert new array structure to old if needed
201→            if (\is_array($decodedValue) && \count($jsonKeyValue) > 0) {
202→                $decodedValue = JsonConfigManagerWrapper::convertToArrayKeyValue($decodedValue, \array_key_first($jsonKeyValue), \array_shift($jsonKeyValue));
203→            }
204→
205→            return $decodedValue;
