211→    /**
212→     * @param $key
213→     * @param null $default
214→     *
215→     * @return \DateTime|null
216→     *
217→     * @throws \RedisException
218→     */
219→    public function getDatetimeOption($key, $default = null)
220→    {
221→        if ($this->has($key)) {
222→            return $this->getDecodedValue($this->arrayConfigValue[$this->cfgIdent][$key]);
223→        }
224→
225→        if (null === $default) {
226→            $default = (new \DateTime('NOW'))->format('Y-m-d H:i:s');
227→        }
228→
229→        return \DateTime::createFromFormat('Y-m-d H:i:s', $default);
