232→    /**
233→     * @param $key
234→     * @param $default
235→     *
236→     * @return bool
237→     *
238→     * @throws \RedisException
239→     */
240→    public function getBoolOption($key, $default): bool
241→    {
242→        if ($this->has($key)) {
