249→    /**
250→     * function that determines whether a key is the type of configuration.
251→     *
252→     * @param [string] $config name of the configuration of the key
253→     * @param [string] $type   type of the configuration of the key
254→     *
255→     * @return bool
256→     */
257→    public function typeOf($key, $type): bool
258→    {
259→        $this->checkIfKeyExistOrCreateException($key);
260→
261→        return $this->arrayConfigValue[$this->cfgIdent][$key]['type'] === $type;
262→    }
