278→    /**
279→     * function that determined whether a key configuration is the equal.
280→     *
281→     * @param [string] $config name of the configuration of the key
282→     * @param [string] $value  value of the configuration of the key
283→     *
284→     * @return bool
285→     */
286→    public function equal($key, $value): bool
287→    {
288→        $this->checkIfKeyExistOrCreateException($key);
289→
290→        return $this->arrayConfigValue[$this->cfgIdent][$key]['value'] === $value;
291→    }
292→
293→    /**
294→     * function to retrieve a list of key configuration via configuration group are.
295→     */
296→    public function getByNamespace(string $q): array
297→    {
298→        $configValue = [];
299→        $input       = preg_quote($q, '~');
300→        $findKey     = preg_grep('~'.$input.'~', array_keys($this->arrayConfigValue[$this->cfgIdent]));
301→        foreach ($findKey as $valueKey) {
302→            $configValue[$valueKey] = $this->get($valueKey);
303→        }
304→
305→        return $configValue;
306→    }
307→
308→    /**
309→     * retrieve config key names for a given query string or.
310→     */
311→    public function getFieldByQueryString(string $q, bool $isGroup = false): array
312→    {
313→        $fieldName = 'id';
314→        $fields    = [];
315→
316→        $currentConfigValues = $this->arrayConfigValue[$this->cfgIdent];
317→        $input               = preg_quote($q, '~');
318→
319→        $pattern = $isGroup ? '/^'.$input.'\./' : '~(?i)'.$input.'~';
320→        $findKey = preg_grep($pattern, array_keys($currentConfigValues));
321→        foreach ($findKey as $valueKey) {
322→            $fields[$valueKey] = $currentConfigValues[$valueKey][$fieldName];
323→        }
324→        if (0 === \count($fields)) {
325→            $fields = ['-1'];
326→        }
327→
328→        return $fields;
329→    }
330→
331→    /**
332→     * is for find and load the configuration value for the create cache.
333→     *
334→     * @throws \Exception
335→     */
336→    protected function loadConfigValues(): void
337→    {
338→        $content = $this->redisCache->get($this->cacheKey);
339→
340→        if (!$content) {
341→            $data = $this->loadFromDatabase();
342→            $this->redisCache->set($this->cacheKey, json_encode($data));
343→        } else {
344→            $data = json_decode($content, true);
345→        }
346→
347→        $this->arrayConfigValue[$this->cfgIdent] = $data;
348→    }
349→
350→    /**
351→     * @param $val
352→     *
353→     * @return array|bool|\DateTime
354→     */
355→    private function getDecodedValue($val)
356→    {
357→        switch (strtolower($val['type'])) {
358→            case 'datetime':
359→                return \DateTime::createFromFormat('Y-m-d H:i:s', $val['value']);
360→            case 'boolean':
361→                return filter_var($val['value'], \FILTER_VALIDATE_BOOLEAN);
362→            case 'integer':
363→                return (int) $val['value'];
364→            case 'decimal':
365→                return (float) $val['value'];
366→            case 'json':
367→                if (null === $val['value']) {
368→                    return [];
369→                }
370→
371→                return json_decode($val['value'], true);
372→            case 'color':
373→                return false === strpos($val['value'], '#') ? '#'.$val['value'] : $val['value'];
374→            case 'string':
375→                if (preg_match('/^\[.*\]$/', $val['value'])) {
376→                    return explode(',', substr($val['value'], 1, -1));
377→                }
378→
379→                return $val['value'];
380→            default:
381→                return $val['value'];
382→        }
383→    }
384→
385→    /**
386→     * function permettant de retourner tous les valeur pour valeur
387→     * des clefs de configuration pour un couple (environnement et webinstance).
388→     *
389→     * @return array
390→     *
391→     * @throws \Exception
392→     */
393→    private function loadFromDatabase()
394→    {
395→        if (RunMode::LINKED === $this->mode) {
396→            $datas['web'] = $this->entityManager
397→                         ->getRepository('ElibertyConfigManagerBundle:Webinstance')
398→                         ->findOneBy(['name' => $this->currentWebinstanceShortname]);
399→        } else {
400→            $datas['web'] = $this->entityManager->find('ElibertyConfigManagerBundle:Webinstance', 1);
401→        }
402→
403→        $datas['env'] = $this->entityManager
404→                         ->getRepository('ElibertyConfigManagerBundle:Environnement')
405→                         ->findOneBy(['name' => $this->currentEnvironnement]);
406→
407→        $listConfig = [];
408→        if (null !== $datas['web'] && null !== $datas['env']) {
409→            $configurationvalues = $this->entityManager
410→                                        ->getRepository('ElibertyConfigManagerBundle:ConfigurationValue')
411→                                        ->getConfigsByWebinstanceAndEnvironnement($datas);
412→
413→            foreach ($configurationvalues as $configvalue) {
414→                $codeGroup = '';
415→                if (null !== $configvalue->getConfiguration()->getGroupConfig()) {
416→                    $codeGroup = $configvalue->getConfiguration()->getGroupConfig()->getCodeAsString();
417→                }
418→
419→                $codeGroupAsString = $codeGroup.'.'.$configvalue->getConfiguration()->getCode();
420→                $value             = $configvalue->getValue() ?? $configvalue->getConfiguration()->getDefaultvalue();
421→
422→                if (!isset($listConfig[$codeGroupAsString])) {
423→                    $listConfig[$codeGroupAsString] = [
424→                        'value' => $value,
425→                        'type'  => $configvalue->getConfiguration()->getConfigtype(),
426→                        'id'    => $configvalue->getConfiguration()->getId(),
427→                    ];
428→                }
429→            }
430→        }
431→
432→        return $listConfig;
433→    }
434→
435→    /**
436→     * check if the key existe into the array or create a exception.
437→     *
438→     * @param $key
439→     *
440→     * @throws \InvalidArgumentException
441→     */
442→    private function checkIfKeyExistOrCreateException($key): void
443→    {
444→        if (!\array_key_exists($key, $this->arrayConfigValue[$this->cfgIdent])) {
445→            throw new \InvalidArgumentException(\sprintf('Inexistant configuration key: %s (cfgIdent: %s)', $key, $this->cfgIdent));
446→        }
447→    }
448→
449→    /**
450→     * delete cache for the configmanager keys.
451→     *
452→     * @throws \RedisException
453→     */
454→    public function dropCache(): void
455→    {
456→        $this->redisCache->del([$this->cacheKey]);
457→    }
458→
459→    /**
460→     * @param $key
461→     * @param $value
462→     *
463→     * @return bool
464→     */
465→    public function setConfigValue($key, $value): bool
466→    {
467→        try {
468→            $this->checkIfKeyExistOrCreateException($key);
469→            $configCacheValue = $this->arrayConfigValue[$this->cfgIdent][$key];
470→            $configValueRepo  = $this->entityManager->getRepository('ElibertyConfigManagerBundle:ConfigurationValue');
471→            $configValue      = $configValueRepo->find($configCacheValue['id']);
472→            $configValue->setValue($value);
473→            $this->entityManager->flush($configValue);
474→
475→            return true;
476→        } catch (\Exception $ex) {
477→            return false;
478→        }
479→    }
480→
481→    /**
482→     * retrieve configuration id for a full key code and webinstance code.
483→     *
484→     * @param $key
485→     * @param string $webinstanceCode
486→     *
487→     * @return mixed
488→     *
489→     * @throws \InvalidArgumentException
490→     */
491→    public function getValueForWebinstance($key, $webinstanceCode)
492→    {
493→        $this->checkIfKeyExistOrCreateException($key);
494→
495→        $configId   = $this->arrayConfigValue[$this->cfgIdent][$key]['id'];
496→        $configType = $this->arrayConfigValue[$this->cfgIdent][$key]['type'];
497→
498→        $configValueRepo = $this->entityManager->getRepository('ElibertyConfigManagerBundle:ConfigurationValue');
499→        $configValue     = $configValueRepo->getConfigForWebinstance($configId, $webinstanceCode, $this->currentEnvironnement);
500→
501→        if (null === $configValue) {
502→            return null;
503→        }
504→
505→        return $this->getDecodedValue(
506→            [
507→                'value' => $configValue,
508→                'type'  => $configType,
509→            ]
510→        );
511→    }
512→
513→    public function hasConfigValueForWebinstance(string $key, string $webinstanceCode): bool
514→    {
515→        if ($this->has($key)) {
516→            $configId = $this->arrayConfigValue[$this->cfgIdent][$key]['id'];
517→            $value    = $this->entityManager->getRepository(ConfigurationValue::class)->getConfigValueForWebinstance($configId, $webinstanceCode, $this->currentEnvironnement);
518→
519→            return null !== $value;
520→        }
521→
522→        return false;
523→    }
524→
525→    public function getWebinstanceShortname(): string
526→    {
527→        return $this->currentWebinstanceShortname;
528→    }
529→
530→    public function getEnvironment(): string
531→    {
532→        return $this->currentEnvironnement;
533→    }
534→
535→    public function getArrayOption(string $key): array
536→    {
537→        if ($this->has($key) && !empty($this->getDecodedValue($this->arrayConfigValue[$this->cfgIdent][$key]))) {
538→            return explode(',', $this->getDecodedValue($this->arrayConfigValue[$this->cfgIdent][$key]));
539→        }
540→
541→        return [];
542→    }
543→}
