 44→    /**
 45→     * @throws ExternalActivityException
 46→     */
 47→    public function getDaysAvailability(Product $product): array
 48→    {
 49→        try {
 50→            $resourceId = $product->getExternalActivityResourceId();
 51→            $path       = sprintf('/api/rest/v1/resources/%s/availabilityunits', $resourceId);
 52→            $client     = $this->restFactory->getClient();
 53→            $params     = $this->apiHelper->getParamDaysAvailability();
 54→            $cacheKey   = $this->apiHelper->getRedisKey('booking_days', $path, $params);
 55→
 56→            $this->apiHelper->logInfo('getDaysAvailability for booking with params', $params);
 57→
 58→            if (!$days = $this->redisCache->get($cacheKey)) {
 59→                $res = $client->get($path, ['query' => $params]);
 60→
 61→                $response = json_decode($res->getBody(), true);
 62→                $days     = $this->apiHelper->getListOfDays($response);
 63→
 64→                if ($this->apiHelper->getCacheExpirationTime() > 0) {
 65→                    $this->redisCache->set($cacheKey, $days, $this->apiHelper->getCacheExpirationTime());
 66→                }
 67→            }
 68→
 69→            return $days;
 70→        } catch (RequestException $requestException) {
 71→            $this->apiHelper->parseAndLogRequestException(__METHOD__, $requestException);
 72→
 73→            throw new ExternalActivityException($requestException);
 74→        } catch (\Exception $e) {
 75→            $this->apiHelper->parseAndLogException(__METHOD__, $e);
 76→
 77→            throw new ExternalActivityException($e);
 78→        }
 79→    }
