 87→            $resourceId = $product->getExternalActivityResourceId();
 88→            $path       = sprintf('/api/rest/v1/resources/%s/units', $resourceId);
 89→            $client     = $this->restFactory->getClient();
 90→            $params     = $this->apiHelper->getParamActivitiesBetweenDates($startDate, $endDate);
 91→
 92→            $this->apiHelper->logInfo('getSubContingentsBetweenDates for booking with params', $params);
 93→
 94→            $res        = $client->get($path, ['query' => $params]);
 95→            $response   = json_decode($res->getBody(), true);
 96→            $activities = $this->apiHelper->getSubContingents($response);
 97→
 98→            foreach ($activities as $activity) {
 99→                $this->em->persist($activity);
