 21→class ApiHelper extends BaseApiHelper
 22→{
 23→    /**
 24→     * @return Collection<SubContingent>
 25→     */
 26→    public function getSubContingents(Result $contingent): Collection
 27→    {
 28→        $base = $contingent['products'][0]['time_slots'][0] ?? [];
 29→
 30→        $timeSlots = $base['available_times_lots_every_day'][0]['time_slots']   ?? null;
 31→        $timeSlots ??= $base['available_times_lots_first_day'][0]['time_slots'] ?? null;
 32→        $timeSlots ??= $base['available_times_lots_last_day'][0]['time_slots']  ?? null;
 33→
 34→        $needToFlush    = false;
 35→        $subContingents = [];
 36→        $maxVelOrder    = $this->configManager->getIntOption('cart.max_overall_quantity', 12);
 37→        $webinstance    = $this->getWebInstance();
 38→
 39→        /** @var SubContingentRepository $subContingentRepository */
 40→        $subContingentRepository = $this->em->getRepository(SubContingent::class);
 41→        foreach ($timeSlots as $timeSlot) {
 42→            $externalId = sprintf('%d-%d-%d', $timeSlot['config_number'], $timeSlot['config_limit_number'], $timeSlot['slotlfd']);
 43→
 44→            $date = \DateTime::createFromImmutable(
 45→                DateTimeImmutable::createFromFormat(\DateTimeInterface::ATOM, $timeSlot['start_time'])
 46→            );
 47→
 48→            /** @var ?SubContingent $subContingent */
 49→            $subContingent = $this->getSubContingent($externalId);
 50→
 51→            if (null === $subContingent) {
 52→                $subContingent = (new SubContingent())
 53→                    ->setWebInstance($webinstance)
 54→                    ->setExternalId($externalId);
 55→
 56→                $subContingentRepository->persist($subContingent);
 57→                $needToFlush = true;
 58→            }
 59→
 60→            $subContingent->setLabel($timeSlot['name'])
 61→                ->setShortname($timeSlot['name'])
 62→                ->setQuotaAvailable($timeSlot['free_space'])
 63→                ->setQuotaInUse($timeSlot['current_reservation'])
 64→                ->setDate($date)
 65→                ->setSalesClosedAt($date)
 66→                ->setType(ExternalBookingProvider::AX_BOOKING)
 67→                ->setLimitQuotaOrderVel($maxVelOrder)
 68→            ;
 69→
 70→            if (!empty($timeSlot['sales_channel'])) {
 71→                $subContingent->setQuotaAvailable($timeSlot['sales_channel']['sales_channel_free']);
 72→            }
 73→
 74→            $subContingents[$externalId] = $subContingent;
 75→        }
 76→
 77→        if ($needToFlush) {
 78→            $subContingentRepository->flush();
 79→        }
 80→
 81→        return new ArrayCollection($subContingents);
 82→    }
