 87→
 88→        /** @var SubContingentRepository $subContingentRepository */
 89→        $subContingentRepository = $this->em->getRepository(SubContingent::class);
 90→
 91→        /** @var ?SubContingent $subContingent */
 92→        return $subContingentRepository->findOneBy([
 93→            'externalId'  => $externalId,
 94→            'webinstance' => $webinstance,
 95→        ]);
