25→            'username'    => $this->trinityConfig['username'],
26→            'password'    => $this->trinityConfig['password'],
27→            'json_fields' => ['username', 'password'],
28→        ]);
29→
30→        $persistenceStrategy = $this->redisPersistence->withCacheKey('trinity_jwt_token');
31→
32→        $authClient = new Client(
33→            [
34→                'base_uri' => $this->trinityConfig['base_url'],
35→                'headers'  => ['Content-Type' => 'application/json'],
36→            ]
37→        );
38→
39→        $jwtManager = new JwtManager(
40→            $authClient,
41→            $authStrategy,
42→            $persistenceStrategy,
43→            [
