29→/**
30→ * Class GenericTagCompilerPass.
31→ */
32→class GenericTagCompilerPass implements CompilerPassInterface
33→{
34→    protected ContainerBuilder $container;
35→
36→    public function process(ContainerBuilder $container): void
37→    {
38→        $this->container = $container;
39→
40→        // Define here the factory service and tag associated ...
41→        $compilerPassesMapping = [
42→            ProxyManagerFactory::class                => 'proxymanager.processor',
43→            KeycardValidatorFactory::class            => 'keycard_validate.processor',
44→            MailFactory::class                        => 'mail.processor',
45→            DynamicPriceHandlerFactory::class         => 'dynamic_price.handler',
46→            AdjustmentProcessorResolver::class        => 'adjustment.processor',
47→            ImportProcessorFactory::class             => 'import.s3.processor',
48→            MailGeneratorResolver::class              => 'mail.generator',
49→            RequestParametersTriggerSubscriber::class => 'tracking.listener',
50→            OrderitemResolverFactory::class           => 'orderitem.resolver',
51→            CartitemResolverFactory::class            => 'cartitem.resolver',
52→            DashboardFactory::class                   => 'dashboard.processor',
53→            ListFieldFactory::class                   => 'admin.list_field',
54→            DatagridFilterFactory::class              => 'admin.datagrid_filter',
55→            ListActionFactory::class                  => 'admin.list_action',
56→            AuthenticationManager::class              => 'authentication.manager',
57→            AssetHandlerFactory::class                => 'asset_handler',
58→            ExternalActivityHandlerFactory::class     => 'external_activity.handler',
59→            Factory::class                            => 'validities_guesser',
60→            PriceProviderFactory::class               => 'price.provider',
61→            PriceResolverFactory::class               => 'price.resolver',
62→        ];
63→
64→        foreach ($compilerPassesMapping as $factoryServiceId => $tagName) {
65→            $this->processCompilerPass($factoryServiceId, $tagName);
66→        }
67→    }
68→
69→    private function processCompilerPass(string $factoryServiceId, string $tagName): void
70→    {
71→        $resolverCollectionDefinition = $this->container->getDefinition($factoryServiceId);
72→        foreach ($this->container->findTaggedServiceIds($tagName) as $serviceId => $tags) {
73→            $resolverCollectionDefinition->addMethodCall(
74→                'add',
75→                [new Reference($serviceId), $serviceId]
76→            );
77→        }
78→    }
79→}
