 11→
 12→class ClientFactory
 13→{
 14→    protected array $contractorConfig = [];
 15→    protected ?string $consigneType   = null;
 16→    protected ?string $local          = null;
 17→    protected ?string $webId          = null;
 18→
 19→    protected ConfigManager $configManager;
 20→    protected LoggerInterface $logger;
 21→
 22→    public function __construct(ConfigManager $configManager, LoggerInterface $loggerSkicase)
 23→    {
 24→        $this->configManager = $configManager;
 25→        $this->logger        = $loggerSkicase;
 26→    }
 27→
 28→    /**
 29→     * @throws \SoapFault
 30→     * @throws \Exception
 31→     */
 32→    public function askReservation(Product $product, \DateTime $from): ?object
 33→    {
 34→        $this->initContractorConfig($product->getCatalog()->getContractor());
 35→        $this->initProductConfig($product);
 36→
 37→        $to       = $this->initEndDate($product, $from);
 38→        $isSeason = $this->isProductSeason($product);
 39→
 40→        $params = [
 41→            'webid'      => $this->webId,
 42→            'nbcons1'    => 1,
 43→            'typecons1'  => $this->consigneType,
 44→            'nbcons2'    => '',
 45→            'typecons2'  => '',
 46→            'nbcons3'    => '',
 47→            'typecons3'  => '',
 48→            'datedeb'    => $from->format('d/m/Y'),
 49→            'datefin'    => $to->format('d/m/Y'),
 50→            'local'      => $this->local,
 51→            'resasaison' => $isSeason ? 1 : 0,
 52→        ];
 53→        $this->logger->info(\sprintf('Koralp ask reservation for product %s', $product->getId()),
 54→            ['params' => $params]);
 55→
 56→        return $this->call('ask_resa', $params);
 57→    }
 58→
 59→    /**
 60→     * Confirm reservation.
 61→     *
 62→     * @throws \SoapFault
 63→     * @throws \Exception
 64→     */
 65→    public function confirmReservation(Product $product, \DateTime $from, int $quantity = 1): ?object
 66→    {
 67→        $this->initContractorConfig($product->getCatalog()->getContractor());
 68→        $this->initProductConfig($product);
 69→
 70→        $to       = $this->initEndDate($product, $from);
 71→        $isSeason = $this->isProductSeason($product);
 72→
 73→        $params = [
 74→            'webid'      => $this->webId,
 75→            'nbcons1'    => $quantity,
 76→            'typecons1'  => $this->consigneType,
 77→            'nbcons2'    => '',
 78→            'typecons2'  => '',
 79→            'nbcons3'    => '',
 80→            'typecons3'  => '',
 81→            'datedeb'    => $from->format('d/m/Y'),
 82→            'datefin'    => $to->format('d/m/Y'),
 83→            'local'      => $this->local,
 84→            'name'       => 'anonymous',
 85→            'mail'       => 'anonymous@anonymous.com',
 86→            'tel'        => '+33606060606',
 87→            'resasaison' => $isSeason ? 1 : 0,
 88→        ];
 89→        $this->logger->info(\sprintf('Koralp confirm reservation for product %s', $product->getId()),
 90→            ['params' => $params]);
 91→
 92→        return $this->call('confirm_resa', $params);
 93→    }
 94→
 95→    /**
 96→     * @throws \SoapFault
 97→     */
 98→    public function confirmPayment(Contractor $contractor, Product $product, int $webId, int $refOrder, ?Contact $payer): ?object
 99→    {
100→        $this->initContractorConfig($contractor);
101→        $this->initProductConfig($product);
102→
103→        $params = [
104→            'webid'    => $webId,
105→            'local'    => $this->local,
106→            'commande' => $refOrder,
107→            'confirm'  => 'yes',
108→        ];
109→
110→        if ($payer instanceof ContactInterface) {
111→            $params = \array_merge($params, [
112→                'name' => $payer->getName(),
113→                'mail' => $payer->getEmail(),
114→                'tel'  => $payer->getMobile() ?: $payer->getPhone(),
115→            ]);
116→        }
117→        $this->logger->info(\sprintf('Koralp confirm payment for contractor %s', $contractor->getId()),
118→            ['params' => $params]);
119→
120→        return $this->call('confirm_paiement', $params);
121→    }
122→
123→    /**
124→     * @throws \SoapFault
125→     */
126→    private function call(string $functionName, array $params): ?object
127→    {
128→        $options = [
129→            'location' => $this->contractorConfig['url'] ?? null,
130→            'uri'      => $this->contractorConfig['uri'] ?? null,
131→            'trace'    => 1,
132→        ];
133→
134→        try {
135→            $client   = new \SoapClient(null, $options);
136→            $response = $client->__call($functionName, $params);
137→
138→            $context = [
139→                'options'  => $options,
140→                'params'   => $params,
141→                'response' => $response,
142→            ];
143→            if ($response->error) {
144→                $message = sprintf('Koralp skicase error %s : %s', $functionName, $response->msgerror);
145→                if ('confirm_paiement' === $functionName) {
146→                    $this->logger->critical($message, $context);
147→                } else {
148→                    $this->logger->error($message, $context);
149→                }
150→            } else {
151→                $this->logger->info(
152→                    sprintf('Koralp skicase call %s : resa possible %s', $functionName, $response->resa_possible),
153→                    $context
154→                );
155→            }
156→
157→            return $response;
158→        } catch (\Exception $e) {
159→            $message = 'Koralp error : '.$e->getMessage();
160→            $context = [
161→                'functionName' => $functionName,
162→                'options'      => $options,
163→                'params'       => $params,
164→            ];
165→            if ('confirm_paiement' === $functionName) {
166→                $this->logger->critical($message, $context);
167→            } else {
168→                $this->logger->error($message, $context);
169→            }
170→
171→            return null;
172→        }
173→    }
174→
175→    private function initContractorConfig(Contractor $contractor): void
176→    {
177→        $skicaseConfig = $this->configManager->getJsonOption('skicase.config', [], ['contractorId' => 'config']);
178→        $contractorId  = $contractor->getId();
179→        $config        = $skicaseConfig[$contractorId] ?? [];
180→        if (empty($config)) {
181→            $message = \sprintf('Koralp skicase config is not configured for contractor %d', $contractorId);
182→            $this->logger->error($message);
183→            throw new \UnexpectedValueException($message);
184→        }
185→        $this->local            = $config['local'];
186→        $this->contractorConfig = $config;
187→    }
188→
189→    private function initProductConfig(Product $product): void
190→    {
191→        [$webId, $consigneType, $local] = array_pad(explode(';', $product->getExternalActivityResourceId()), 3, null);
192→
193→        $this->consigneType = $consigneType;
194→        $this->webId        = $webId;
195→
196→        if (null !== $local) {
197→            $this->local = $local;
198→        }
199→    }
200→
201→    private function isProductSeason(Product $product): bool
202→    {
203→        $validityCategoryShortname = $product->getValiditycategory()->getShortname();
204→
205→        return false !== stripos($validityCategoryShortname, 'season') || false !== stripos($validityCategoryShortname, 'annual');
206→    }
207→
208→    /**
209→     * @throws \Exception
210→     */
211→    private function initEndDate(Product $product, \DateTime $from): \DateTime
212→    {
213→        $delta = 'P1D';
214→        $to    = clone $from;
215→
216→        if ($this->isProductSeason($product)) {
217→            $domain = $product->getProductcategory();
218→            if (null === $domain->getValidTo()) {
219→                $message = \sprintf('Valid To date for Domain of the product %s must be defined', $product->getId());
220→                $this->logger->error($message);
221→                throw new \RuntimeException($message);
222→            }
223→
224→            return $domain->getValidTo();
225→        }
226→
227→        $validityCategory = $product->getValidityCategory();
228→
229→        if (null !== $valueValidityCategory = $validityCategory->getValue()) {
230→            $delta = sprintf('P%sD', $valueValidityCategory - 1);
231→        } else {
232→            $this->logger->warning(\sprintf('No value for Validity Category %s (Product %s), %s was defined',
233→                $validityCategory->getId(), $product->getId(), $delta));
234→        }
235→
236→        return $to->add(new \DateInterval($delta));
237→    }
238→}
