 5→namespace Eliberty\RedpillBundle\ApiClient\Infra\Token;
 6→
 7→use Eliberty\RedpillBundle\Exception\ApiTokenException;
 8→use Eliberty\RedpillBundle\Helper\JWTHelper;
 9→
10→/**
11→ * JwtToken set token and manage its expiration time.
12→ */
13→class JwtToken implements TokenInterface
14→{
15→    private ?string $token = null;
16→
17→    private ?int $expirationTime = null;
18→
19→    /**
20→     * Set the token value.
21→     *
22→     * @throws ApiTokenException
23→     */
24→    public function set(string $token): self
25→    {
26→        $this->token = $token;
27→
28→        try {
29→            /** @var array{exp: int} $decodedToken */
30→            $decodedToken = JWTHelper::decodeToken($this->token);
31→        } catch (\JsonException $e) {
32→            throw new ApiTokenException(sprintf('Invalid decoded json value for token[%s]', $this->token));
33→        }
34→
35→        $this->expirationTime = $decodedToken['exp'] ?? 0;
36→
37→        return $this;
38→    }
39→
40→    /**
41→     * Get the token value.
42→     */
43→    public function get(): ?string
44→    {
45→        return $this->token;
46→    }
47→
48→    /**
49→     * Is the token expired ?
50→     *
51→     * @param int $ttlSafetyMargin safety margin of seconds (10s by default) to avoid mistake with ttl limit
52→     */
53→    public function isExpired(int $ttlSafetyMargin = 10): bool
54→    {
55→        if ($this->expirationTime) {
56→            return $ttlSafetyMargin >= $this->getTtl();
57→        }
58→
59→        return false;
60→    }
61→
62→    /**
63→     * Get the token remaining time to live in seconds or null if no expiration time.
64→     */
65→    public function getTtl(): ?int
66→    {
67→        if ($this->expirationTime) {
68→            return $this->expirationTime - time();
69→        }
70→
71→        return null;
72→    }
73→}
