 23→use Symfony\Contracts\HttpClient\HttpClientInterface;
 24→
 25→/**
 26→ * AuthJwtApiClient is an authenticated api client with token-based authentication.
 27→ *
 28→ * Token-based authentication process :
 29→ *  - if token not found by its discriminant parameters (more or less main_uri and username)
 30→ *  -   first call login to get token (like JWT)
 31→ *  -   store token
 32→ *  - main call is authenticated with stored token
 33→ *  - if invalid/expired token response
 34→ *  -   re-call login to get token
 35→ *  -   store token
 36→ *  -   main call retry
 37→ */
 38→class AuthJwtApiClient extends ApiClientParameters implements ApiClientInterface
 39→{
 40→    protected ApiClientInterface $apiClient;
 41→
 42→    protected ApiTokenInterface $apiToken;
 43→
 44→    protected TokenErrorInterface $tokenError;
 45→
 46→    protected LoggerInterface $logger;
 47→
 48→    protected IdentityService $identityService;
 49→
 50→    /**
 51→     * $apiParameters require (key*:) or can have (key?:) keys below :
 52→     * - base_uri|discriminant_uri*: string ('base_uri' key will be set as 'main_uri' key if it used with $apiConfigParams and discriminant_uri is required if the base_uri already set into http-client)
