class GenericTagCompilerPass implements CompilerPassInterface {
    public function process(ContainerBuilder $container): void {
        $compilerPassesMapping = [
            // ...
            ExternalActivityHandlerFactory::class => 'external_activity.handler',
        ];

        foreach ($compilerPassesMapping as $factoryServiceId => $tagName) {
            $resolverCollectionDefinition = $container->getDefinition($factoryServiceId);
            foreach ($container->findTaggedServiceIds($tagName) as $serviceId => $tags) {
                $resolverCollectionDefinition->addMethodCall(
                    'add',
                    [new Reference($serviceId), $serviceId]
                );
            }
        }
    }
}
